import { Component, OnInit, computed, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { Router, RouterLink } from '@angular/router';
import { ApiService } from '../../core/api.service';
import { CartItem } from '../../core/models';

/**
 * Storefront checkout (`checkout`, authGuard). Ship-to form + order summary.
 * On submit calls ApiService.placeOrder(); surfaces the backend 400
 * insufficient-stock message inline. On success redirects to /orders.
 */
@Component({
  selector: 'app-checkout',
  standalone: true,
  imports: [CommonModule, FormsModule, RouterLink],
  templateUrl: './checkout.component.html',
  styleUrl: './checkout.component.css',
})
export class CheckoutComponent implements OnInit {
  shipName = '';
  shipAddress = '';
  readonly submitting = signal(false);
  readonly error = signal<string | null>(null);

  // Mock cart lines for the summary — service_agent replaces with ApiService.getCart().items.
  readonly items = signal<CartItem[]>([
    {
      id: 'ci1',
      cartId: 'c1',
      productId: 'p1',
      qty: 1,
      product: {
        id: 'p1',
        name: 'Aurora Wireless Headphones',
        description: '',
        priceCents: 18900,
        imageUrl: '',
        stockQty: 24,
      },
    },
    {
      id: 'ci2',
      cartId: 'c1',
      productId: 'p2',
      qty: 2,
      product: {
        id: 'p2',
        name: 'Terra Insulated Bottle',
        description: '',
        priceCents: 3200,
        imageUrl: '',
        stockQty: 120,
      },
    },
  ]);

  readonly totalCents = computed(() =>
    this.items().reduce((sum, i) => sum + (i.product?.priceCents ?? 0) * i.qty, 0),
  );

  constructor(private api: ApiService, private router: Router) {}

  ngOnInit(): void {
    this.api.getCart().subscribe({
      next: (cart) => this.items.set(cart.items ?? []),
      error: () => {},
    });
  }

  submit(): void {
    if (!this.shipName.trim() || !this.shipAddress.trim()) {
      this.error.set('Enter a shipping name and address.');
      return;
    }
    this.submitting.set(true);
    this.error.set(null);
    this.api.placeOrder({ shipName: this.shipName, shipAddress: this.shipAddress }).subscribe({
      next: (order) => {
        this.submitting.set(false);
        this.router.navigate(['/orders', order.id]);
      },
      error: (err) => {
        this.submitting.set(false);
        // Surfaces e.g. "Insufficient stock for Grove Ceramic Mug Set".
        this.error.set(err?.error?.message || 'Checkout failed. Please review your cart and try again.');
      },
    });
  }

  money(cents: number): string {
    return '$' + (cents / 100).toFixed(2);
  }
}
